static void F_SendDebugDataOnCan_v(void)
{
  /* DD-ID: {3B47B910-0363-4308-BEDC-2DD0324C6623}*/
  static uint8 V_PmicRstRsn_u8 = 0x00;
  static uint8 V_RstRsn_u8 = 0x00;
  static uint32 V_Reset_Reason_u32;
  static uint32 V_RstRsnDebugCan_u32;
  static uint16 V_BswMCanTxOnCAN_u16;
  static uint8_t V_CAN_Tx_Err_Reason_u8 = 0x00;
  uint8 v_ResetVal_u8 = (uint8)e_ZERO;
  V_Reset_Reason_u32 = f_get_reset_register();
  for (v_ResetVal_u8 = (uint8)e_ZERO; v_ResetVal_u8 < RESET_REGISTER_BIT_POSITION_MAX; v_ResetVal_u8++)
  {
     if(CHECK_BIT(V_Reset_Reason_u32,(uint32)e_ONE << v_ResetVal_u8)!= 0u)
     {
      if((uint8)e_ONE == V_Reset_Reason_u32)
      {
        V_RstRsn_u8 = (uint8)V_Reset_Reason_u32; /* Soft Reset */
      }
      else
      {
        V_RstRsn_u8 = v_ResetVal_u8;
      }
      break;
     }
     else
     {
      /*Do Nothing*/
     }
  }

  /* Store the reboot reason value in 1st byte */
  if((uint8)e_ZERO != pmic_utils_getLastReset())
  {
      V_PmicRstRsn_u8 = pmic_utils_getLastReset();
  }
  else if(TRUE == v_FdF2HookErrorStatus)
  {
      if((uint8)e_ONE == s_ME_OsHookDebugData_RPRAM_as.FD14_1_Hook_Type_MCU1_0)
	  {
		  V_PmicRstRsn_u8 = SAFESTATE_REASON_OS_ERROR_HOOK;
	  }
      else if((uint8)e_TWO == s_ME_OsHookDebugData_RPRAM_as.FD14_1_Hook_Type_MCU1_0)
	  {
		  V_PmicRstRsn_u8 = SAFESTATE_REASON_OS_PROTECTION_HOOK;
	  }
	  else
	  {
		  V_PmicRstRsn_u8 = SAFESTATE_REASON_OS_PANIC_HOOK;
	  }
  }
  /*
   * Add Case for WdgReset
  else if(TRUE == v_FdF2HookErrorStat)
  {
	  V_PmicRstRsn_u8 = s_ME_OsHookDebugData_RPRAM_as.FD14_1_Hook_Type_MCU1_0;
  }*/
  else
  {
      V_PmicRstRsn_u8 = (uint8)e_ZERO;
  }

V_RstRsnDebugCan_u32 = (uint32)V_RstRsn_u8;
V_RstRsnDebugCan_u32 |= (uint32)LEFTSHIFT_BIT((uint32)V_PmicRstRsn_u8,BIT_SHIFT_EIGHT_BIT);
V_RstRsnDebugCan_u32 |= (uint32)LEFTSHIFT_BIT((uint32)Rte_Safety_Guard_SafeStat2_ResetReason_MirrorBlock_copy,BIT_SHIFT_SIXTEEN_BIT);
(void)Rte_Write_PpToComDbgFD14Tx_FD14_TimeStamp_SystemStatus(V_RstRsnDebugCan_u32);

V_BswMCanTxOnCAN_u16 = (uint16)V_CAN_Tx_Err_Reason_u8;
V_BswMCanTxOnCAN_u16 |= (uint16)LEFTSHIFT_BIT((uint16)BswM_Switch_ESH_ModeSwitch_BswM_MDGP_ESH_Mode,BIT_SHIFT_EIGHT_BIT);
(void)Rte_Write_PpToComDbgFD14Tx_FD14_SystemMode(V_BswMCanTxOnCAN_u16);

}

