static void TX_VCANProcess(void)
{
  uint8 reqItemIndex;
static EventDataManage_t TX_VCAN_EventDataManage[E_TX_VCAN_Last_EventIndex] =
{
    /*EventID		                               isTriggered_b		EventType_u8		               CounterValue_u32		  PeriodicityTypes_u32		FuncPtrWrite*/	
  { E_TX_FROMSWC_TOCOM_Process1000_mSecSignal,        0U,              D_TIME_TRIGGERED_EVENT,       0U,                  THOUSAND,                   &TX_FROMSWC_TOCOM_Process1000_mSecSignal },
  { E_TX_Vcan_EVENT_TX_FROMSWC_TOCOM,                 0U,              D_EXTERNAL_TRIGGERED_EVENT,   0U,                  0U,                     &TX_Vcan_EVENT_TX_FROMSWC_TOCOM },

};

  /* DD-ID: {3A21CB3F-5111-4231-BDFD-381CAFAA39A7}*/
  for(reqItemIndex = (uint8)E_TX_FROMSWC_TOCOM_Process1000_mSecSignal; reqItemIndex < (uint8)E_TX_VCAN_Last_EventIndex; reqItemIndex++)
  {
    if(TX_VCAN_EventDataManage[reqItemIndex].EventType_u8 == D_TIME_TRIGGERED_EVENT)
    {
          TX_VCAN_EventDataManage[reqItemIndex].CounterValue_u32+=TASKREPRATE;
          if(TX_VCAN_EventDataManage[reqItemIndex].CounterValue_u32 >= TX_VCAN_EventDataManage[reqItemIndex].PeriodicityTypes_u32)
          {
              TX_VCAN_EventDataManage[reqItemIndex].CounterValue_u32 = TASKREPRATE;
              TX_VCAN_EventDataManage[reqItemIndex].isTriggered_b = (uint8)e_ONE;
          }
    }
    else if(TX_VCAN_EventDataManage[reqItemIndex].EventType_u8 == D_EXTERNAL_TRIGGERED_EVENT)
    {
      TX_VCAN_EventDataManage[reqItemIndex].FuncPtrWrite();
    }
	else
	{
		/*Do Nothing*/
	}
  }
  
  for(reqItemIndex =(uint8)e_ZERO; reqItemIndex < (uint8)E_TX_VCAN_Last_EventIndex; reqItemIndex++)
  {
        if(TX_VCAN_EventDataManage[reqItemIndex].isTriggered_b == (uint8)e_ONE)
      {
          TX_VCAN_EventDataManage[reqItemIndex].isTriggered_b = (uint8)e_ZERO;
          TX_VCAN_EventDataManage[reqItemIndex].FuncPtrWrite();
          
      }
  }
}

